div.p:
1. Function Entry
rust
fn process_data() {
yield_if_preempted(); // ✅ SAFE
// Prologue complete
}

2. Loop Backedge
rust
for i in 0..1_000_000 {
compute_step(i);
yield_if_preempted(); // ✅ SAFE
}

5. Function Exit
rust
fn compute() -> Result {
yield_if_preempted(); // ✅ SAFE
return Ok(result);
}

1. Mid-Expression
rust
// ❌ UNSAFE
let result = a + compute() * b;
// Partial results in registers

2. Inside malloc/free
rust
// ❌ UNSAFE
let ptr = allocate(size);
// Heap invariants in flux

3. Lock Operations
rust
// ❌ UNSAFE
mutex.lock();
critical_section();
mutex.unlock();

4. FFI Boundary
rust
// ❌ UNSAFE
unsafe {
let result = c_library_call();
}

5. Signal Handler
rust
// ❌ UNSAFE
extern "C" fn handler(sig: c_int) {
// Reentrancy issues
}

DeferPreemptionGuard (RAII)
rust
{
let _guard = defer_preemption();
acquire_lock();
modify_shared_state();
release_lock();
}

Lock Tracking
rust
fn should_defer_preemption() -> bool {
LOCKS_HELD.with(|c| c.get() > 0)
}

CPU-Bound Loop
rust
for chunk in data.chunks_mut(1024) {
process_chunk(chunk);
yield_if_preempted();
}

Producer-Consumer
rust
async fn producer(queue: &Queue) {
loop {
let item = generate_item();
queue.send(item).await;
yield_if_preempted();
}
}

Recursive Processing
rust
fn traverse(node: &Node, depth: u32) {
if depth % 100 == 0 { yield_if_preempted(); }
for child in &node.children {
traverse(child, depth + 1);
}
}
